// q8_gemv.cu — custom in-kernel Q8_0 dequant + GEMV for single-token decode.
//
// WHY (proven by measurement): GPU decode with cuBLAS is VRAM-BANDWIDTH-bound —
// it must read the f16 weights (~14.5 GB/token) at ~300 GB/s → a ~48 ms floor.
// The fix is to read FEWER bytes: keep the weights resident as RAW Q8_0 bytes
// (~7.7 GB) and dequantize IN-KERNEL (cuBLAS cannot consume block-scaled Q8).
// 7.7 GB / 300 GB/s ≈ 26 ms → ~20 tps with NO quality loss (Q8 is the knot).
//
// Q8_0 block layout (matches llama.cpp / dequantize_q8_0_row in math.rs):
//   34 bytes per block of 32 elements:
//     bytes [0..2)  : f16 scale `d` (little-endian IEEE half)
//     bytes [2..34) : 32 signed int8 quants `q`
//   dequant(elem) = __half2float(d) * (float)q
// A weight row of K elements is K/32 contiguous blocks; the weight matrix is
// row-major [N rows × K], i.e. row r starts at byte offset r * (K/32) * 34.
//
// out[r] = Σ_k dequant(W[r,k]) * x[k]   for r in [0, N)
//
// ─────────────────────────────────────────────────────────────────────────
// THREAD/WORK MAPPING (optimized for memory throughput):
//   ONE WARP (32 lanes) computes ROWS_PER_WARP output rows; WARPS_PER_BLOCK
//   warps per CUDA block. blockDim.x = 32 * WARPS_PER_BLOCK.
//   gridDim.x  = ceil(N / (WARPS_PER_BLOCK * ROWS_PER_WARP)).
//   Each lane strides over each row's (K/32) Q8 blocks with stride 32.
//   Reduction is warp-shuffle ONLY — no __syncthreads on the reduce path.
//
// TWO BANDWIDTH LEVERS over the previous (correct, 152 GB/s) version:
//
//   (A) STAGE x IN SHARED MEMORY (kills redundant x traffic). Every warp in a
//       CUDA block reads the SAME input x (same layer). Previously each of the
//       8 warps re-read x from global/L2 → 8× redundant x traffic. When K is
//       small enough to fit (K * 4 bytes <= shared budget), the block loads x
//       into shared ONCE (coalesced, all threads), __syncthreads, then every
//       warp reads x from shared. For K=4096 (q/k/v/o/gate/up) that is 16 KB,
//       well under the 48 KB classic shared limit. For K=14336 (down-proj
//       input) x is 57 KB > shared → we fall back to __ldg global x (the host
//       passes shared_mem_bytes=0 for that case so the array is empty/unused).
//       The host decides via the same K threshold and sets shared_mem_bytes.
//
//   (B) ROWS_PER_WARP > 1 (raise arithmetic intensity, reuse staged x). A warp
//       computes ROWS_PER_WARP independent rows in one pass over x. The x reads
//       (from shared, cheap) and the per-lane control overhead are amortized
//       across multiple weight rows, and the grid shrinks by the same factor so
//       the shared-x stage is paid by more useful work. The weight bytes (the
//       62 MB cost) are still each read exactly once — different rows read
//       different weights — so this does not change weight traffic, it hides its
//       latency behind more in-flight FMAs and fewer redundant x fetches.
//
// VECTORIZED LOADS:
//   * x (when global): float4 (xbase = b*32 is a multiple of 4 → 16B aligned
//     vs the ≥256B-aligned base pointer). x in shared is read scalar (shared
//     has no alignment penalty and no DRAM cost).
//   * The 32 int8 quants of a block start at block+2. The block stride is 34
//     (not a multiple of 16/4), so the quant offset is only 2-byte-aligned in
//     general. We copy the 32 quants into a 16-byte-aligned local via
//     `__builtin_memcpy` of a COMPILE-TIME-CONSTANT 32 bytes: nvcc lowers this
//     to the widest load it can prove safe for the source's alignment (down to
//     byte loads if needed) — NEVER a faulting over-aligned wide load. Once in
//     registers the bytes are read back through a signed-char view.
//
// All read-only global loads go through __ldg (read-only data cache) and the
// pointers are __restrict__.
//
// Build: compiled to a native sm_89 CUBIN at build time by build.rs via
// `nvcc --cubin -arch=sm_89`; at runtime the cudarc DRIVER loads the CUBIN
// (cuModuleLoadData) — no NVRTC at runtime. Numerics match
// dequantize_q8_0_row exactly: per-block scale * Σ(q*x), float accumulate.

#include <cuda_fp16.h>

// Warps per CUDA block. blockDim.x MUST equal 32 * WARPS_PER_BLOCK and the
// Rust launch's Q8K_BLOCK_DIM MUST match.
#define WARPS_PER_BLOCK 8
// Output rows computed by each warp in a single pass over x. The host grid is
// ceil(N / (WARPS_PER_BLOCK * ROWS_PER_WARP)); Q8K_ROWS_PER_WARP MUST match.
#define ROWS_PER_WARP 2

// Max K (elements) for which x is staged in shared memory. The shared array is
// sized to this; the host passes shared_mem_bytes = min(K, SHARED_X_MAX_K)*4
// and only enables staging when K <= SHARED_X_MAX_K. 8192 floats = 32 KB,
// under the 48 KB default shared cap, and covers all K=4096 GEMVs while the
// K=14336 down-proj input takes the global path.
#define SHARED_X_MAX_K 8192

// The kernel body is templated on the ACCUMULATOR type so we can emit two
// entry points from ONE definition:
//   * q8_gemv     — ACC=double (f64): order-independent, required for mamba-2.8b's
//     chaotic S6 scan (argmax sensitive to ~1e-5 projection perturbations).
//   * q8_gemv_f32 — ACC=float (f32): ~2-3× faster on the L4 (Ada f64 is ~1/64 f32,
//     and f32 halves register pressure → higher occupancy → closer to the DRAM-bound
//     floor). Selected per-model at launch (MESH_GPU_Q8K_F32) for decoders that are
//     NOT argmax-sensitive to summation order (Mamba-2 SSD scalar-A-per-head is far
//     more stable than S6). Parity-gated per model before enabling.
template <typename ACC>
__device__ __forceinline__ void q8_gemv_impl(
    const unsigned char* __restrict__ W, // raw Q8_0 bytes, row-major [N × K]
    const float* __restrict__ x,         // activation vector, length K
    float* __restrict__ out,             // output vector, length N
    int N,
    int K)
{
    const int warp_id = threadIdx.x >> 5;        // 0 .. WARPS_PER_BLOCK-1
    const int lane    = threadIdx.x & 31;        // 0 .. 31

    const int blocks_per_row = K >> 5;           // K / 32 (K is a multiple of 32)
    const size_t row_bytes   = (size_t)blocks_per_row * 34;

    // (A) Optional shared staging of x. The launch sets dynamic shared to
    //   K*4 bytes ONLY when K <= SHARED_X_MAX_K; otherwise shared_mem_bytes==0
    //   and we MUST NOT touch xsh (read x from global instead). `use_shared` is
    //   uniform across the block, so the __syncthreads below is not divergent.
    extern __shared__ float xsh[];
    const bool use_shared = (K <= SHARED_X_MAX_K);
    if (use_shared) {
        // Cooperative coalesced load of all K floats into shared, ONCE per block.
        for (int i = threadIdx.x; i < K; i += blockDim.x) {
            xsh[i] = __ldg(x + i);
        }
        __syncthreads();
    }

    // (B) This warp owns ROWS_PER_WARP rows starting at row0. Bounds-checked
    //   per row below (the last block may be partially out of range).
    const int warp_global = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const int row0        = warp_global * ROWS_PER_WARP;
    if (row0 >= N) return;

    // Per-row accumulators for this lane (one per row this warp computes).
    // DOUBLE accumulation (was float): mamba-2.8b's S6 selective scan is a chaotic
    // amplifier — the next-token argmax is sensitive to ~1e-5 perturbations in the
    // projection outputs, so this GEMV's f32 warp-parallel summation ORDER (vs the
    // CPU's naive sequential f32 sum that serves the correct token) tips the argmax
    // to an unrelated token even though cos>0.9999. Accumulating in f64 converges
    // this kernel to the true (order-independent) math, matching the exact CPU
    // reference. Transformers never reach this kernel (they ship Q4K/Q6K, not raw
    // Q8), so this cannot regress them; f64 adds is a few extra cycles per block,
    // negligible next to the DRAM-bound weight reads this kernel is optimized for.
    ACC partial[ROWS_PER_WARP];
    #pragma unroll
    for (int r = 0; r < ROWS_PER_WARP; ++r) partial[r] = (ACC)0;

    // Stride over the row's blocks; each lane handles blocks { lane, lane+32, … }.
    for (int b = lane; b < blocks_per_row; b += 32) {
        const int xbase = b << 5;                // first x index of this block

        // Load this block's 32 x values ONCE and reuse across all ROWS_PER_WARP
        // rows (x is identical per row). From shared (cheap, no DRAM) when
        // staged, else float4 global. Held in 8 float4 registers (32 floats) —
        // not a 32-float array — to keep register pressure low.
        float4 xv0, xv1, xv2, xv3, xv4, xv5, xv6, xv7;
        if (use_shared) {
            const float4* __restrict__ xs4 =
                reinterpret_cast<const float4*>(xsh + xbase);
            xv0 = xs4[0]; xv1 = xs4[1]; xv2 = xs4[2]; xv3 = xs4[3];
            xv4 = xs4[4]; xv5 = xs4[5]; xv6 = xs4[6]; xv7 = xs4[7];
        } else {
            const float4* __restrict__ xb =
                reinterpret_cast<const float4*>(x + xbase);
            xv0 = __ldg(xb + 0); xv1 = __ldg(xb + 1);
            xv2 = __ldg(xb + 2); xv3 = __ldg(xb + 3);
            xv4 = __ldg(xb + 4); xv5 = __ldg(xb + 5);
            xv6 = __ldg(xb + 6); xv7 = __ldg(xb + 7);
        }

        #pragma unroll
        for (int r = 0; r < ROWS_PER_WARP; ++r) {
            const int row = row0 + r;
            if (row >= N) continue;              // tail guard (constant trip count)
            const unsigned char* __restrict__ row_ptr = W + (size_t)row * row_bytes;
            const unsigned char* __restrict__ bp = row_ptr + (size_t)b * 34;

            // f16 scale: first 2 bytes, little-endian IEEE half. 2-byte
            // unaligned-safe load; reinterpret as __half (same bit layout as the
            // CPU's u16::from_le_bytes -> f16_to_f32).
            unsigned short raw_d;
            __builtin_memcpy(&raw_d, bp, sizeof(unsigned short));
            const float scale = __half2float(*reinterpret_cast<const __half*>(&raw_d));

            // 32 signed int8 quants at bp+2 (only 2-byte-aligned: block stride 34).
            // memcpy of a COMPILE-TIME-CONSTANT 32 → nvcc emits the widest load it
            // can prove safe (never a faulting over-aligned wide load). int4[2]
            // destination gives a 16-byte-aligned local for the register repack.
            union { int4 v[2]; signed char c[32]; } q;
            __builtin_memcpy(&q, bp + 2, 32);

            // scale * Σ(q*x). The 32 per-block products are f32 (matches the CPU
            // dequant*x element math) but summed into a DOUBLE block accumulator,
            // and the per-block contributions accumulate into the f64 `partial`
            // (see the accumulator decl above for why f64 is required for mamba).
            // Products in DOUBLE: q is int8 (exact) and each x lane is f32 (exact
            // in f64), so (double)q*(double)x is the exact product — no f32
            // multiply rounding. Summed in double, this block dot is order-robust.
            ACC blk = (ACC)0;
            blk += (ACC)q.c[ 0]*(ACC)xv0.x + (ACC)q.c[ 1]*(ACC)xv0.y + (ACC)q.c[ 2]*(ACC)xv0.z + (ACC)q.c[ 3]*(ACC)xv0.w;
            blk += (ACC)q.c[ 4]*(ACC)xv1.x + (ACC)q.c[ 5]*(ACC)xv1.y + (ACC)q.c[ 6]*(ACC)xv1.z + (ACC)q.c[ 7]*(ACC)xv1.w;
            blk += (ACC)q.c[ 8]*(ACC)xv2.x + (ACC)q.c[ 9]*(ACC)xv2.y + (ACC)q.c[10]*(ACC)xv2.z + (ACC)q.c[11]*(ACC)xv2.w;
            blk += (ACC)q.c[12]*(ACC)xv3.x + (ACC)q.c[13]*(ACC)xv3.y + (ACC)q.c[14]*(ACC)xv3.z + (ACC)q.c[15]*(ACC)xv3.w;
            blk += (ACC)q.c[16]*(ACC)xv4.x + (ACC)q.c[17]*(ACC)xv4.y + (ACC)q.c[18]*(ACC)xv4.z + (ACC)q.c[19]*(ACC)xv4.w;
            blk += (ACC)q.c[20]*(ACC)xv5.x + (ACC)q.c[21]*(ACC)xv5.y + (ACC)q.c[22]*(ACC)xv5.z + (ACC)q.c[23]*(ACC)xv5.w;
            blk += (ACC)q.c[24]*(ACC)xv6.x + (ACC)q.c[25]*(ACC)xv6.y + (ACC)q.c[26]*(ACC)xv6.z + (ACC)q.c[27]*(ACC)xv6.w;
            blk += (ACC)q.c[28]*(ACC)xv7.x + (ACC)q.c[29]*(ACC)xv7.y + (ACC)q.c[30]*(ACC)xv7.z + (ACC)q.c[31]*(ACC)xv7.w;
            partial[r] += (ACC)scale * blk;
        }
    }

    // Warp-shuffle reduction across the 32 lanes for each row → lane 0 writes.
    // Reduce in DOUBLE (CUDA 9+/sm_89 supports __shfl_down_sync for double) so the
    // cross-lane sum keeps the f64 precision the per-lane accumulation earned; the
    // final store narrows to the f32 `out` buffer.
    const unsigned FULL = 0xffffffffu;
    #pragma unroll
    for (int r = 0; r < ROWS_PER_WARP; ++r) {
        ACC p = partial[r];
        #pragma unroll
        for (int offset = 16; offset > 0; offset >>= 1) {
            p += __shfl_down_sync(FULL, p, offset);
        }
        const int row = row0 + r;
        if (lane == 0 && row < N) {
            out[row] = (float)p;
        }
    }
}

// f64 accumulation — order-independent, the safe default (mamba-2.8b S6 needs it).
extern "C" __global__ void q8_gemv(
    const unsigned char* __restrict__ W, const float* __restrict__ x,
    float* __restrict__ out, int N, int K)
{
    q8_gemv_impl<double>(W, x, out, N, K);
}

// f32 accumulation — ~2-3× faster on the L4; for decoders not argmax-sensitive to
// summation order (parity-gated per model, e.g. Codestral Mamba-2 SSD).
extern "C" __global__ void q8_gemv_f32(
    const unsigned char* __restrict__ W, const float* __restrict__ x,
    float* __restrict__ out, int N, int K)
{
    q8_gemv_impl<float>(W, x, out, N, K);
}
